const lang = $('Detect Language (Ollama)').item.json.response.trim().toLowerCase();
const character = $('Get Character Persona').item.json;
const interactionType = $json.body.type || 'welcome';
const nsfw_level = $json.body.subscriber_tier === 'vip' ? 8
  : $json.body.subscriber_tier === 'premium' ? 6
  : $json.body.subscriber_tier === 'basic' ? 4 : 0;

// Embudo de ingeniería social basado en nivel
const funnelCTA = {
  0:  { cta: '😊 Sígueme para más contenido gratis',        platform: 'free' },
  2:  { cta: '🔞 Preview exclusivo → Telegram',              platform: 'telegram' },
  4:  { cta: '💕 Pack completo $15 → Gumroad + Fansly',      platform: 'gumroad+fansly' },
  6:  { cta: '🔥 VIP Pack $25 → Gumroad + Fanvue',           platform: 'gumroad+fanvue' },
  8:  { cta: '⭐ Colección VIP $40 → 4 plataformas',         platform: 'gumroad+patreon+fansly+fanvue' },
  10: { cta: '🎯 Contenido custom PPV → DM directo',         platform: 'gumroad+itchio+fansly' }
};
const funnel = funnelCTA[nsfw_level] || funnelCTA[0];

const personaTemplates = {
  'miyuki_sakura': {
    'younger_sister': {
      'en': 'Hi! Thanks for reaching out! 😊',
      'ja': 'こんにちは！メッセージありがとうございます！✨',
      'es': '¡Hola! ¡Gracias por escribirme! 💕'
    }
  },
  'aiko_hayashi': {
    'boss_authority': {
      'en': 'Welcome to my office. I hope you have been productive today. 💼',
      'ja': '私のオフィスへようこそ。今日の仕事は順調ですか？💼',
      'es': 'Bienvenido a mi oficina. Espero que hayas sido productivo hoy. 💼'
    }
  }
};

const characterPersonaTemplate = personaTemplates[character.id] || personaTemplates['miyuki_sakura'];
const personaMode = character.persona_mode || 'younger_sister';
const responseTemplate = characterPersonaTemplate[personaMode]?.[lang]
  || characterPersonaTemplate[personaMode]?.['en'] || '';

return {
  detected_lang: lang,
  response_text: responseTemplate + '\n\n' + funnel.cta,
  character_id: character.id,
  trigger_word: character.trigger_word,
  follower_username: $json.body.username,
  nsfw_level,
  funnel_platforms: funnel.platform,
  interaction_type: interactionType
};

