const result = $input.item.json;
const platforms = Object.keys(result).filter(k => result[k]?.ok);
const failed = Object.keys(result).filter(k => result[k] && !result[k]?.ok);

return {
  published_count: platforms.length,
  published_platforms: platforms.join(', ') || 'ninguna',
  failed_platforms: failed.join(', ') || 'ninguna',
  summary: `✅ Publicado en: ${platforms.join(', ')}` + (failed.length ? `\n❌ Fallido en: ${failed.join(', ')}` : ''),
  raw_results: result
};

